// Accept body from webhook (POST body is in .body or top-level)
const body = $input.first().json.body || $input.first().json;

const firstName = (body.firstName || '').trim();
const lastName  = (body.lastName  || '').trim();
const email     = (body.email     || '').trim().toLowerCase();
const rating    = parseInt(body.rating) || 0;
const message   = (body.message   || '').trim();
const fullName  = [firstName, lastName].filter(Boolean).join(' ');

// Validate required fields
if (!firstName || !email || rating < 1 || rating > 5 || !message) {
  throw new Error('WF2: Missing or invalid fields — requires firstName, email, rating (1–5), message');
}

// Escape single quotes for SQL embedding
const esc = (s) => (s || '').replace(/'/g, "''");

// Star display for email
const stars = '\u2605'.repeat(rating) + '\u2606'.repeat(5 - rating);

// --- Thank you email to the client ---
const clientHtml = [
  '<div style="font-family:sans-serif;max-width:600px;margin:0 auto">',
  '<h2 style="color:#2D6A6A;margin-bottom:16px">Thank You, ' + firstName + '!</h2>',
  '<p style="line-height:1.7;color:#333">Thank you for taking the time to share your experience with SoulSynergy Coaching. Your testimonial means the world!</p>',
  '<p style="line-height:1.7;color:#333">Your submission will appear on the website after a brief review. We are grateful for your trust and support on this journey.</p>',
  '<p style="line-height:1.7;color:#333">Warmly,<br><strong>Arushi Bhardwaj</strong><br>SoulSynergy Coaching</p>',
  '<hr style="border:none;border-top:1px solid #eee;margin:24px 0">',
  '<p style="color:#999;font-size:12px">SoulSynergy Coaching &mdash; Uncover. Align. Achieve.</p>',
  '</div>'
].join('');

// --- Notification email to Arushi ---
const arushiHtml = [
  '<div style="font-family:sans-serif;max-width:600px;margin:0 auto">',
  '<h2 style="color:#2D6A6A;margin-bottom:16px">New Testimonial Submitted</h2>',
  '<table style="border-collapse:collapse;width:100%;font-size:14px">',
  '<tr><td style="padding:12px;border:1px solid #ddd;background:#f5f5f5;width:120px"><strong>Name</strong></td>',
  '<td style="padding:12px;border:1px solid #ddd">' + fullName + '</td></tr>',
  '<tr><td style="padding:12px;border:1px solid #ddd;background:#f5f5f5"><strong>Email</strong></td>',
  '<td style="padding:12px;border:1px solid #ddd"><a href="mailto:' + email + '" style="color:#2D6A6A">' + email + '</a></td></tr>',
  '<tr><td style="padding:12px;border:1px solid #ddd;background:#f5f5f5"><strong>Rating</strong></td>',
  '<td style="padding:12px;border:1px solid #ddd">' + stars + ' (' + rating + '/5)</td></tr>',
  '<tr><td style="padding:12px;border:1px solid #ddd;background:#f5f5f5"><strong>Testimonial</strong></td>',
  '<td style="padding:12px;border:1px solid #ddd;white-space:pre-wrap">' + message + '</td></tr>',
  '</table>',
  '<p style="font-size:14px;color:#555;margin-top:16px">Review and publish via your admin portal when ready.</p>',
  '<p style="color:#999;font-size:12px">Saved to Neon DB automatically &mdash; <code>is_published = false</code> until you approve it.</p>',
  '</div>'
].join('');

const clientResendPayload = JSON.stringify({
  from: 'SoulSynergy Coaching <onboarding@resend.dev>',
  to: [email],
  subject: 'Thank you for your testimonial, ' + firstName + '!',
  html: clientHtml
});

const arushiResendPayload = JSON.stringify({
  from: 'SoulSynergy Coaching <onboarding@resend.dev>',
  to: ['connect.sscoach@gmail.com'],
  subject: '\u2B50 New Testimonial: ' + fullName + ' \u2014 ' + rating + '/5',
  html: arushiHtml
});

return [{
  json: {
    // SQL-safe values (single quotes escaped)
    first_name:            esc(firstName),
    last_name:             esc(lastName),
    email:                 esc(email),
    message:               esc(message),
    full_name:             esc(fullName),
    rating:                rating,
    // Raw values (for use in emails — not SQL)
    raw_email:             email,
    raw_full_name:         fullName,
    raw_first_name:        firstName,
    // Pre-built Resend payloads
    client_resend_payload: clientResendPayload,
    arushi_resend_payload: arushiResendPayload
  }
}];
